#!/bin/bash
# Platform run.sh for E_baseline_organizer — mode=organizer
# see README.md §1 (Hypothesis & Claim).
# Generated by skills/_helpers/build_cloud_package.py — do not hand-edit on platform.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "$0")" && pwd)"
export PYTHONPATH="${SCRIPT_DIR}:${PYTHONPATH:-}"

# ---------------------------------------------------------------------------
# Platform must set TRAIN_DATA_PATH and TRAIN_CKPT_PATH. Other paths derive.
# ---------------------------------------------------------------------------
: "${TRAIN_DATA_PATH:?TRAIN_DATA_PATH not set by platform}"
: "${TRAIN_CKPT_PATH:?TRAIN_CKPT_PATH not set by platform}"
: "${TRAIN_LOG_PATH:=${TRAIN_CKPT_PATH}/logs}"
: "${TRAIN_TF_EVENTS_PATH:=${TRAIN_CKPT_PATH}/tf_events}"
: "${TRAIN_WORK_PATH:=${TRAIN_CKPT_PATH}/work}"
mkdir -p "${TRAIN_CKPT_PATH}" "${TRAIN_LOG_PATH}" "${TRAIN_TF_EVENTS_PATH}" "${TRAIN_WORK_PATH}"
export TRAIN_LOG_PATH TRAIN_TF_EVENTS_PATH

echo "[run.sh] DATA=${TRAIN_DATA_PATH}"
echo "[run.sh] CKPT=${TRAIN_CKPT_PATH}"
echo "[run.sh] mode=organizer"

# ---------------------------------------------------------------------------
# Train (organizer baseline as-shipped — row-group split, no OOF).
# Note: this path ASSUMES schema.json already exists at TRAIN_DATA_PATH/schema.json
# (organizer ships one alongside production data; verified for /data_ams/...).
# ---------------------------------------------------------------------------
# Smoke-test defaults tuned for Taiji + CFS (verified on production: 2.1M rows,
# 1000 parquet files). Goal: produce a valid val_AUC + checkpoint in <60 min.
#
#   --num_workers 2          (8 deadlocks DataLoader; 0 starves GPU at ~5.9s/step)
#   --buffer_batches 4       (default 20 causes 12s flush spike every 20 steps)
#   --train_ratio 0.05       (use first 5% of train row groups; full epoch ~10h
#                             at default 1.0; 5% gives a quick sanity result)
#   --seq_max_lens ...       (default 256/256/512/512; halved attention cost)
#
# Override any of these at runtime, e.g.:
#   bash run.sh --train_ratio 0.5 --seq_max_lens seq_a:256,seq_b:256,seq_c:512,seq_d:512
python3 -u "${SCRIPT_DIR}/train.py" \
    --num_epochs 1 \
    --patience 5 \
    --seed 42 \
    --ns_tokenizer_type rankmixer \
    --user_ns_tokens 5 \
    --item_ns_tokens 2 \
    --num_queries 2 \
    --ns_groups_json "" \
    --emb_skip_threshold 1000000 \
    --num_workers 2 \
    --buffer_batches 4 \
    --train_ratio 0.05 \
    --seq_max_lens "seq_a:64,seq_b:64,seq_c:128,seq_d:128" \
    "$@"

echo "[run.sh] training complete (organizer pure); metrics at ${TRAIN_CKPT_PATH}/metrics.json"
